const fs = require('fs');
const path = require('path');
const SELECTED_PRODUCT = 'ERP';
const resultsDir = 'c:/Users/veeramani/.gemini/antigravity/scratch/Automation Workflow/temp_results';
if (fs.existsSync(resultsDir)) {
  fs.readdirSync(resultsDir).forEach(f => { try { fs.unlinkSync(path.join(resultsDir, f)); } catch (e) {} });
} else {
  fs.mkdirSync(resultsDir, { recursive: true });
}
const products = {
  'ERP': { product: 'ERP', folder: 'ERP', description: 'Run all ERP test scripts' },
  'Camp': { product: 'Camp', folder: 'CampAccomodation', description: 'Run all Camp Accommodation test scripts' }
};
return [{ json: products[SELECTED_PRODUCT] }];

const fs = require('fs');
const items = $input.all();
const product = items[0].json.product;
const folder = items[0].json.folder;
const fullPath = `c:/Users/veeramani/.gemini/antigravity/scratch/Automation Workflow/tests/${folder}`;
const returnData = [];
try {
  if (!fs.existsSync(fullPath)) return [{ json: { product, folder, error: 'Dir not found', fileCount: 0 } }];
  const testFiles = fs.readdirSync(fullPath).filter(f => f.endsWith('.spec.js'));
  testFiles.forEach(file => {
    returnData.push({ json: { product, folder, filename: file, fullPath: `${fullPath}/${file}`, testPath: `tests/${folder}/${file}` } });
  });
  return returnData;
} catch (error) {
  return [{ json: { product, folder, error: error.message, fileCount: 0 } }];
}

const { execSync } = require('child_process');
const item = $input.item.json;
if (item.error) return { json: { ...item, exitCode: -1, status: 'skipped', stats: { total: 0, passed: 0, failed: 0 } } };
const cmd = `npx playwright test "${item.testPath}" --reporter=json`;
const cwd = 'c:/Users/veeramani/.gemini/antigravity/scratch/Automation Workflow';
const startTime = new Date();
let stdout = '', stderr = '', exitCode = 0;
try {
  stdout = execSync(cmd, { cwd, stdio: 'pipe', timeout: 600000 }).toString();
} catch (e) {
  exitCode = e.status || 1;
  stdout = (e.stdout || '').toString();
  stderr = (e.stderr || e.message || '').toString();
}
const duration = ((new Date() - startTime) / 1000).toFixed(2);
let testCases = [], stats = { total: 0, passed: 0, failed: 0 }, reportSummary = '', screenshotPath = null;
try {
  const jsonMatch = stdout.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const jsonData = JSON.parse(jsonMatch[0]);
    if (jsonData.stats) {
      stats.passed = jsonData.stats.expected || 0;
      stats.failed = jsonData.stats.unexpected || 0;
      stats.total = stats.passed + stats.failed + (jsonData.stats.skipped || 0);
    }
    if (jsonData.suites) {
      jsonData.suites.forEach(suite => {
        (suite.specs || []).forEach(spec => {
          spec.tests.forEach(test => {
            const res = test.results && test.results[0];
            if (res && res.attachments) {
               const ss = res.attachments.find(a => a.name === 'screenshot');
               if (ss && !screenshotPath) screenshotPath = ss.path;
            }
            testCases.push({ title: spec.title, status: res ? res.status : 'unknown' });
          });
        });
      });
    }
    reportSummary = testCases.map(tc => `${tc.status === 'passed' ? '✅' : '❌'} ${tc.title}`).join('\\n');
  }
} catch (e) {}
const combined = stdout + '\\n' + stderr;
const jsonStart = combined.lastIndexOf('{"stats":');
const logs = jsonStart !== -1 ? combined.substring(0, jsonStart).trim() : combined.trim();
const errorDetails = logs.replace(/\\[MCP\\] ✅ Called \\\/\\w+/g, '').trim();
return { json: { ...item, exitCode, errorDetails: errorDetails || (exitCode === 0 ? 'No errors' : 'Failed'), status: exitCode === 0 ? 'passed' : 'failed', duration: `${duration}s`, timestamp: new Date().toISOString(), stats, reportSummary, screenshotPath: screenshotPath ? (screenshotPath.includes(':') || screenshotPath.startsWith('/') ? screenshotPath : `${cwd}/${screenshotPath}`).replace(/\\/g, '/') : null } };

